"""The three Strategy families + the Factories that build them.

This is where the design lives. The service and Coupon depend only on the
three interfaces here — never on the concrete classes.
"""
from __future__ import annotations

from abc import ABC, abstractmethod
from typing import Iterable, List, Optional

from models import Cart, CouponValidationError, DiscountType, ScopeType


# ── 1) DiscountPolicy: HOW MUCH to take off a base amount ─────────────────────
# 🎙️ "First Strategy axis. Given a base amount, return the discount. Percentage
#      and flat are just two implementations; BOGO would be a third."
class DiscountPolicy(ABC):
    @abstractmethod
    def compute(self, base: int) -> int:
        ...

    @abstractmethod
    def describe(self) -> str:
        ...


class PercentageDiscount(DiscountPolicy):
    def __init__(self, percent: int, max_discount: Optional[int] = None):
        # WHY: validate at the boundary — a 150% coupon must be rejected at
        #      creation, never silently applied.
        if not 1 <= percent <= 100:
            raise CouponValidationError("percent must be between 1 and 100")
        if max_discount is not None and max_discount <= 0:
            raise CouponValidationError("max_discount must be positive")
        self.percent = percent
        self.max_discount = max_discount

    def compute(self, base: int) -> int:
        # WHY: integer division on minor units — deterministic, no float drift.
        raw = base * self.percent // 100
        return min(raw, self.max_discount) if self.max_discount is not None else raw

    def describe(self) -> str:
        cap = f" up to {self.max_discount}" if self.max_discount else ""
        return f"{self.percent}% off{cap}"


class FlatDiscount(DiscountPolicy):
    def __init__(self, amount: int):
        if amount <= 0:
            raise CouponValidationError("flat amount must be positive")
        self.amount = amount

    def compute(self, base: int) -> int:
        # WHY: never give back more than the eligible base.
        return min(self.amount, base)

    def describe(self) -> str:
        return f"flat {self.amount} off"


# ── 2) Applicability: WHICH items form the discountable base ──────────────────
# 🎙️ "Second axis — scope. A global coupon's base is the whole cart; a
#      seller/product coupon's base is only the matching lines. This is why I
#      don't just discount cart.total blindly."
class Applicability(ABC):
    @abstractmethod
    def applicable_base(self, cart: Cart) -> int:
        ...

    @abstractmethod
    def describe(self) -> str:
        ...


class GlobalScope(Applicability):
    def applicable_base(self, cart: Cart) -> int:
        return cart.total

    def describe(self) -> str:
        return "all products"


class SellerScope(Applicability):
    def __init__(self, seller_id: str):
        if not seller_id:
            raise CouponValidationError("seller_id required for seller scope")
        self.seller_id = seller_id

    def applicable_base(self, cart: Cart) -> int:
        return sum(i.line_total for i in cart.items if i.seller_id == self.seller_id)

    def describe(self) -> str:
        return f"items from seller '{self.seller_id}'"


class ProductScope(Applicability):
    def __init__(self, product_ids: Iterable[str]):
        ids = set(product_ids)
        if not ids:
            raise CouponValidationError("product_ids required for product scope")
        # WHY set: O(1) membership test per cart item.
        self.product_ids = ids

    def applicable_base(self, cart: Cart) -> int:
        return sum(i.line_total for i in cart.items if i.product_id in self.product_ids)

    def describe(self) -> str:
        return f"products {sorted(self.product_ids)}"


# ── 3) EligibilityCondition: WHETHER the cart qualifies (Specification) ───────
# 🎙️ "Third axis — conditions. Each is a tiny spec that answers yes/no AND
#      gives a human reason for the rejection message."
class EligibilityCondition(ABC):
    @abstractmethod
    def is_satisfied(self, cart: Cart) -> bool:
        ...

    @abstractmethod
    def reason(self) -> str:
        ...


class MinCartValue(EligibilityCondition):
    def __init__(self, min_value: int):
        if min_value <= 0:
            raise CouponValidationError("min_value must be positive")
        self.min_value = min_value

    def is_satisfied(self, cart: Cart) -> bool:
        return cart.total >= self.min_value

    def reason(self) -> str:
        return f"cart total must be at least {self.min_value}"


class MinProductCount(EligibilityCondition):
    def __init__(self, min_count: int):
        if min_count <= 0:
            raise CouponValidationError("min_count must be positive")
        self.min_count = min_count

    def is_satisfied(self, cart: Cart) -> bool:
        return cart.item_count >= self.min_count

    def reason(self) -> str:
        return f"cart must contain at least {self.min_count} products"


# ── Factories: primitive seller API -> strategy objects ──────────────────────
# 🎙️ "The seller passes enums and numbers; the factory turns them into the
#      right strategy. Keeps the service API friendly, the internals polymorphic."
class DiscountFactory:
    @staticmethod
    def create(dtype: DiscountType, value: int,
               max_discount: Optional[int] = None) -> DiscountPolicy:
        if dtype is DiscountType.PERCENTAGE:
            return PercentageDiscount(value, max_discount)
        if dtype is DiscountType.FLAT:
            return FlatDiscount(value)
        raise CouponValidationError(f"unknown discount type: {dtype}")


class ApplicabilityFactory:
    @staticmethod
    def create(stype: ScopeType, scope_ref: Optional[object] = None) -> Applicability:
        if stype is ScopeType.GLOBAL:
            return GlobalScope()
        if stype is ScopeType.SELLER:
            return SellerScope(scope_ref)  # type: ignore[arg-type]
        if stype is ScopeType.PRODUCT:
            # scope_ref is an iterable of product ids
            return ProductScope(scope_ref)  # type: ignore[arg-type]
        raise CouponValidationError(f"unknown scope type: {stype}")

"""Data layer — in-memory coupon store.

Deliberately thin and dumb: it stores and finds, nothing else. All rules live
in the service. Swapping this for a real DB later changes only this file.
"""
from __future__ import annotations

from typing import Dict, List, Optional

from models import Coupon, DuplicateCouponError


class CouponRepository:
    # ── WHY THIS CLASS ───────────────────────────────────────────────────────
    # The single source of truth for stored coupons. The service goes through
    # it for every read/write — that's the data/service separation the brief
    # explicitly grades.
    # 🎙️ "Pure data layer. A dict keyed by code gives O(1) lookup, which is the
    #      hot path since buyers apply by code."
    def __init__(self) -> None:
        self._by_code: Dict[str, Coupon] = {}

    def save(self, coupon: Coupon) -> None:
        # WHY: enforce code uniqueness here — the store owns that invariant.
        if coupon.code in self._by_code:
            raise DuplicateCouponError(f"coupon '{coupon.code}' already exists")
        self._by_code[coupon.code] = coupon

    def find_by_code(self, code: str) -> Optional[Coupon]:
        return self._by_code.get(code)

    def all(self) -> List[Coupon]:
        return list(self._by_code.values())
